# BUG: Division by zero occurs when `numbers` is empty because `len(numbers)` is 0.
def find_average(numbers):
    if not numbers:
        return 0.0
    total = 0
    for n in numbers:
        total = total + n
    return total / len(numbers)

result = find_average([])
print(result)

# BUG: The loop checks all the way up to n-1 instead of stopping at sqrt(n), causing unnecessary work for large primes.

def is_prime(n):
    if n < 2:
        return False
    for i in range(2, int(n ** 0.5) + 1):
        if n % i == 0:
            return False
    return True

print(is_prime(1))      # Should print False
print(is_prime(4))      # Should print False
print(is_prime(1000003))  # Should print True quickly

