# BUG: When arr[mid] < target, setting left = mid can cause an infinite loop or skip elements; it should be left = mid + 1.

def binary_search(arr, target):
    left, right = 0, len(arr)
    while left < right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid
    return -1

print(binary_search([1, 3, 5, 7, 9], 3))
